    (function() {
      var sections = Array.prototype.slice.call(document.querySelectorAll('.section-final'));
      if (!sections.length) return;

      function getTranslateY(el) {
        if (!el || !window || !window.getComputedStyle) return 0;

        var transform = window.getComputedStyle(el).transform;
        if (!transform || transform === 'none') return 0;

        if (transform.indexOf('matrix3d(') === 0) {
          var matrix3dValues = transform
            .slice(9, -1)
            .split(',')
            .map(function(value) { return parseFloat(value.trim()); });
          return Number.isFinite(matrix3dValues[13]) ? matrix3dValues[13] : 0;
        }

        if (transform.indexOf('matrix(') === 0) {
          var matrixValues = transform
            .slice(7, -1)
            .split(',')
            .map(function(value) { return parseFloat(value.trim()); });
          return Number.isFinite(matrixValues[5]) ? matrixValues[5] : 0;
        }

        return 0;
      }

      function needsFix(section) {
        var namesEl = section.querySelector('.final-names');
        var thanksEl = section.querySelector('.final-thanks');
        if (!namesEl || !thanksEl) return false;

        section.classList.remove('editor-final-overlap-fix');

        var namesRect = namesEl.getBoundingClientRect();
        var thanksRect = thanksEl.getBoundingClientRect();
        var thanksTranslateY = getTranslateY(thanksEl);
        var projectedThanksTop = thanksRect.top - Math.max(0, thanksTranslateY);
        var minimumGap = 42;

        return namesRect.bottom + minimumGap > projectedThanksTop;
      }

      function applyFixState() {
        sections.forEach(function(section) {
          if (needsFix(section)) {
            section.classList.add('editor-final-overlap-fix');
          }
        });
      }

      var rafToken = null;
      function scheduleApplyFixState() {
        if (rafToken !== null) {
          cancelAnimationFrame(rafToken);
        }
        rafToken = requestAnimationFrame(function() {
          rafToken = null;
          applyFixState();
        });
      }

      applyFixState();
      setTimeout(applyFixState, 120);
      setTimeout(applyFixState, 600);
      setTimeout(applyFixState, 1200);

      window.addEventListener('resize', scheduleApplyFixState);
      window.addEventListener('load', scheduleApplyFixState);

      if (document.fonts && document.fonts.ready) {
        document.fonts.ready.then(scheduleApplyFixState).catch(function() {});
      }

      if (document.fonts && document.fonts.addEventListener) {
        document.fonts.addEventListener('loadingdone', scheduleApplyFixState);
      }

      document.addEventListener('input', function(event) {
        if (event && event.target && event.target.closest && event.target.closest('.section-final')) {
          scheduleApplyFixState();
        }
      }, true);

      if (typeof MutationObserver !== 'undefined') {
        sections.forEach(function(section) {
          var observer = new MutationObserver(scheduleApplyFixState);
          observer.observe(section, {
            subtree: true,
            childList: true,
            characterData: true,
          });
        });
      }
    })();
